INSERT INTO `bot_respuestas` VALUES (1,1,'EVENTO_SISTEMA','SALUDO_NUEVO','Hola! Bienvenido a STARFI Corp. Para brindarte una mejor atención, por favor ind¡canos tu nombre y apellido.','ACTIVO','2026-05-20 08:17:21'),(2,1,'EVENTO_SISTEMA','SALUDO_RECURRENTE','Hola {{nombre}}! Que bueno tenerte de vuelta. En que podemos ayudarte el día de hoy?','ACTIVO','2026-05-20 08:17:21'),(3,1,'EVENTO_SISTEMA','ESPERA_HUMANO','Gracias por la información. En breves momentos un asesor humano te atenderá.','ACTIVO','2026-05-20 08:17:21'),(4,1,'PALABRA_CLAVE','precio, precios, costo, valor, cuanto cuesta, presupuesto','Nuestros precios van según  el servicio que requieras. Para una cotización exacta, un asesor se comunicaría contigo enseguida. Mientras tanto, puedes conocer mis en nuestro sitio web.','ACTIVO','2026-05-20 08:20:01'),(5,1,'PALABRA_CLAVE','ubicacion, donde estan, direccion, oficina','Nuestra sede principal se encuentra en la Av. Principal, Edificio Empresarial, Piso 3. Estaremos encantados de recibirte en nuestras oficinas!','ACTIVO','2026-05-20 08:20:01'),(6,1,'PALABRA_CLAVE','horario, horas, a que hora abren, trabajan los fines de semana','Nuestro horario de atención al cliente es de Lunes a Viernes, de 8:00 AM a 5:00 PM (Hora local).','ACTIVO','2026-05-20 08:20:01'),(7,1,'PALABRA_CLAVE','soporte, ayuda, problema, falla, no funciona','Lamentamos el inconveniente. Hemos derivado tu caso al equipo técnico y te contactarían a la brevedad posible para brindarte soporte.','ACTIVO','2026-05-20 08:20:01'),(8,1,'PALABRA_CLAVE','gracias, excelente, muy amable, ok, perfecto, vale','A ti por preferirnos! Estamos siempre a tu disposición para lo que necesites. Que tengas un excelente día !','ACTIVO','2026-05-20 08:20:01');
