--
-- Table structure for table `mensajes_y_eventos`
--

DROP TABLE IF EXISTS `mensajes_y_eventos`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `mensajes_y_eventos` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `id_conversacion` int(11) NOT NULL,
  `id_mensaje_meta` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `tipo` enum('TEXTO','IMAGEN','DOCUMENTO','EVENTO_SISTEMA') COLLATE utf8mb4_unicode_ci DEFAULT 'TEXTO',
  `origen` enum('CLIENTE','BOT','AGENTE','API_TRANSACCIONAL') COLLATE utf8mb4_unicode_ci NOT NULL,
  `contenido` text COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `estado_envio` enum('ENVIADO','ENTREGADO','LEIDO','FALLIDO') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `url_archivo` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `mime_type` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `timestamp` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `id_conversacion` (`id_conversacion`),
  CONSTRAINT `mensajes_y_eventos_ibfk_1` FOREIGN KEY (`id_conversacion`) REFERENCES `conversaciones` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=654 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

