CREATE TABLE `notificacion_enviada` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `id_api_sede` int(11) DEFAULT NULL,
  `tipo_notificacion` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
