  `fecha` date DEFAULT NULL,
  `hora` time DEFAULT NULL,
  `telefono_emisor` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `telefono_receptor` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `contenido` varchar(300) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `id_evento` int(11) DEFAULT NULL,
  `message_id` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status_whatsapp` enum('SENT','DELIVERED','READ','FAILED') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `fecha_entregado` datetime DEFAULT NULL,
  `fecha_leido` datetime DEFAULT NULL,
  `error_detalle` text COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `metadata` text COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=110 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
